// Behavioral coverage of `connection.insertInto(t).defaultValues()`,
// which triggers `_buildInsertDefaultValues` in each SqlBuilder. Each
// dialect emits its own form, pinned per cell by the snapshot below.

import { afterAll, beforeAll, beforeEach, describe, expect, test } from '../../../../lib/testRunner.js'
import { Table } from '../../../../../src/Table.js'
import { DBConnection } from '../../domain/connection.js'
import { ctx } from './setup.js'

// Local-only table whose only column is an autogenerated PK, so
// `RequiredColumnsForSetOf` resolves to `never` here and `.defaultValues()`
// types correctly with no cast needed.
class TDefaultsOnly extends Table<DBConnection, 'TDefaultsOnly'> {
    id = this.autogeneratedPrimaryKey('id', 'int')
    constructor() { super('defaults_only_table_only_for_sql_test') }
}
const tDefaultsOnly = new TDefaultsOnly()

describe(ctx.label, () => {
    beforeAll(() => ctx.up(), ctx.timeoutMs)
    afterAll(() => ctx.down(), ctx.timeoutMs)
    beforeEach(() => { ctx.reset() })

    test('insert default values', async () => {
        ctx.mockNext(99)
        let id: number | undefined
        let thrownError: unknown
        try {
            id = await ctx.conn.insertInto(tDefaultsOnly)
                .defaultValues()
                .returningLastInsertedId()
                .executeInsert()
        } catch (e) {
            // The table is absent from the schema, so the real INSERT fails
            // referencing the missing relation.
            thrownError = e
        }
        expect(ctx.lastSql).toMatchInlineSnapshot(`"insert into defaults_only_table_only_for_sql_test default values returning id"`)
        expect(ctx.lastParams).toMatchInlineSnapshot(`[]`)
        if (ctx.realDbEnabled) {
            expect((thrownError as Error).message).toMatch(/defaults_only_table_only_for_sql_test|does not exist|relation/)
        } else {
            expect(id).toBe(99)
        }
    })
})
